/**
 * @fileoverview Avatar component — modular entry point.
 * @module module/Avatar
 */

import { default as razyui } from '../../index.js';
import { CLS, DEFAULTS, PART } from './constants.js';
import { setupDOM } from './view.js';

const Avatar = class {
    #root   = null;
    #config = {};
    #els    = {};

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Avatar: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#els = setupDOM(root, this.#config);
    }

    /** Update the avatar image source. */
    setSrc(src) {
        if (this.#els.$image) {
            this.#els.$image.attr('src', src).show();
        } else {
            const $img = PART.IMAGE.create({
                src,
                alt: this.#config.alt || '',
                draggable: false,
            });
            this.#root.prepend($img);
            this.#els.$image = $img;
        }
        if (this.#els.$initials) {
            this.#els.$initials.hide();
        }
    }

    /** Update initials text. */
    setInitials(text) {
        if (this.#els.$initials) {
            this.#els.$initials.text(text.slice(0, 2));
        }
    }

    get element() { return this.#root[0]; }
};

export default Avatar;
